'use server';

import { google } from 'googleapis';
import { createClient } from '@supabase/supabase-js';

const SITE_URL = process.env.NEXT_PUBLIC_SITE_URL || 'https://intimacy.ma';
const SITEMAP_URL = `${SITE_URL}/sitemap.xml`;

// Use private SUPABASE_URL if available, fallback to public (not ideal but works)
const SUPABASE_URL = process.env.SUPABASE_URL || process.env.NEXT_PUBLIC_SUPABASE_URL!;
const SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY!;

if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) {
    throw new Error("Supabase URL or Service Role Key missing.");
}

// Initialize Supabase Admin Client (Service Role)
const supabaseAdmin = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

// --- Types ---
export type QueueItem = {
    id: string;
    url: string;
    status: 'pending' | 'processing' | 'completed' | 'failed' | 'retry';
    updated_at: string;
    created_at: string;
    priority?: 'high' | 'normal' | 'low';
    publish_attempted_at?: string;
    next_retry_at?: string;
    last_error?: string;
    response_status?: number;
};

// --- Helper: Google Auth Client ---
function getGoogleAuth() {
    const raw = process.env.GOOGLE_INDEXING_KEY;
    if (!raw) throw new Error("Missing GOOGLE_INDEXING_KEY.");

    const key = JSON.parse(raw); // Let it throw if invalid JSON

    if (!key.client_email || !key.private_key) {
        throw new Error("GOOGLE_INDEXING_KEY must include client_email and private_key.");
    }

    // Fix newlines in private key
    const privateKey = key.private_key.replace(/\\n/g, "\n");

    return new google.auth.JWT({
        email: key.client_email,
        key: privateKey,
        scopes: ["https://www.googleapis.com/auth/indexing"],
    });
}

// 1. Fetch Sitemap URLs
export async function getSitemapUrls(): Promise<{ url: string; lastmod: number }[]> {
    console.log(`­ƒöì Fetching sitemap from ${SITEMAP_URL}...`);
    try {
        const response = await fetch(SITEMAP_URL, { next: { revalidate: 0 } });
        if (!response.ok) throw new Error(`Failed to fetch sitemap: ${response.statusText}`);
        const xml = await response.text();

        const items: { url: string; lastmod: number }[] = [];

        // Robust extraction: split by <url>
        const urlBlocks = xml.split(/<\/?url>/);

        for (const block of urlBlocks) {
            if (!block.trim()) continue;

            const locMatch = block.match(/<loc>\s*(https?:\/\/[^<]+)\s*<\/loc>/i);
            const modMatch = block.match(/<lastmod>\s*([^<]+)\s*<\/lastmod>/i);

            if (locMatch) {
                const url = locMatch[1].trim();
                const lastmod = modMatch ? new Date(modMatch[1]).getTime() : 0;
                items.push({ url, lastmod });
            }
        }
        // return sorted by newest
        return items.sort((a, b) => b.lastmod - a.lastmod);
    } catch (e: unknown) {
        console.error("Error fetching sitemap:", e);
        throw new Error(e instanceof Error ? e.message : String(e));
    }
}

// 2. Add URLs to Queue
// Internal helper for queuing with Priority
async function internalQueueItems(items: { url: string; priority?: 'high' | 'normal' | 'low' }[]) {
    if (!items.length) return { success: true, count: 0 };

    const rows = items.map(item => ({
        url: item.url,
        status: 'pending',
        priority: item.priority || 'normal'
    }));

    const { error } = await supabaseAdmin
        .from('indexing_queue')
        .upsert(rows, { onConflict: 'url', ignoreDuplicates: true });

    if (error) throw new Error(error.message);
    return { success: true, count: items.length };
}

// 2. Add URLs to Queue (Public wrapper)
export async function addToQueue(urls: string[]) {
    return internalQueueItems(urls.map(url => ({ url })));
}

// 3. Get Queue Stats
export async function getQueueStats() {
    const { data, error } = await supabaseAdmin.from('indexing_queue').select('status');
    if (error) throw new Error(error.message);

    const stats: Record<string, number> = {
        pending: 0,
        processing: 0,
        completed: 0,
        failed: 0,
        retry: 0,
        total: data.length
    };

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    data.forEach((row: any) => {
        const s = row.status || 'pending';
        stats[s] = (stats[s] || 0) + 1;
    });

    return stats;
}

// 4. Get Queue Items (for List)
export async function getQueueItems(statusFilter: string = 'all', limit: number = 50) {
    let query = supabaseAdmin
        .from('indexing_queue')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(limit);

    if (statusFilter !== 'all') {
        query = query.eq('status', statusFilter);
    }

    const { data, error } = await query;
    if (error) throw new Error(error.message);
    return data as QueueItem[];
}

// 5. PROCESS QUEUE BATCH (Production Hardened)
export async function processQueueBatch(limit: number = 10) {
    // A. Check Rolling 24h Quota (Correct Google Logic)
    // We count actual attempts made in the last 24h
    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();

    const { count: attemptsLast24h, error: countError } = await supabaseAdmin
        .from('indexing_queue')
        .select('*', { count: 'exact', head: true })
        // We need to count rows where publish_attempted_at > 24h ago
        // Note: Multiple attempts on same row technically count as multiple quota hits, 
        // but our basic schema tracks only the *last* attempt timestamp. 
        // This is an acceptable approximation: if we retry a row, the old timestamp is overwritten, 
        // so we might *under-count* slightly if we retry same URL multiple times in 24h.
        // For a perfect system we'd need a separate 'indexing_logs' table.
        // Given complexity constraints, we stick to this approximation which is vastly better than counting 'completed'.
        .gte('publish_attempted_at', oneDayAgo);

    if (countError) throw new Error(countError.message);

    const DAILY_LIMIT = 200;
    const remaining = DAILY_LIMIT - (attemptsLast24h || 0);

    if (remaining <= 0) {
        return { success: false, message: "Daily quota exhausted (200 attempts in last 24h). Try again later." };
    }

    // Logic: process at most `limit` or `remaining`, whichever is smaller
    const effectiveLimit = Math.min(limit, remaining);
    if (effectiveLimit <= 0) return { success: true, processed: 0, message: "Quota reached." };

    // B. Atomic Claim via RPC (Prioritized & Retry-Aware)
    // claim_indexing_tasks logic: status='pending' OR status='retry' and next_retry_at <= now()
    const { data: claims, error: claimError } = await supabaseAdmin
        .rpc('claim_indexing_tasks', { limit_count: effectiveLimit });

    if (claimError) throw new Error(claimError.message);
    if (!claims || claims.length === 0) {
        return { success: true, processed: 0, message: "No actionable items (pending or ready for retry)." };
    }

    // C. Auth (Robust: Client Request)
    const jwtClient = getGoogleAuth();
    // No explicit authorize() call needed for request(), it handles token refresh.

    let successCount = 0;
    let failCount = 0;
    let quotaHit = false;

    // D. Sequential Processing
    for (const item of claims) {
        if (quotaHit) {
            // Release remaining claimed items back to their previous state
            // Simplest: set to 'pending' so they are picked up next time (or 'retry' if they were retries?)
            // We'll set to 'pending' to be safe.
            await supabaseAdmin.from('indexing_queue').update({ status: 'pending' }).eq('id', item.id);
            continue;
        }

        try {
            // 1. Mark attempt timestamp (for quota tracking)
            await supabaseAdmin.from('indexing_queue').update({
                publish_attempted_at: new Date().toISOString()
            }).eq('id', item.id);

            // 2. Make Request
            const res = await jwtClient.request({
                url: 'https://indexing.googleapis.com/v3/urlNotifications:publish',
                method: 'POST',
                data: {
                    url: item.url,
                    type: 'URL_UPDATED',
                }
            });

            const status = res.status;

            if (status === 200) {
                await supabaseAdmin.from('indexing_queue').update({
                    status: 'completed',
                    updated_at: new Date().toISOString(),
                    response_status: 200,
                    last_error: null
                }).eq('id', item.id);
                successCount++;
            } else if (status === 429) {
                // QUOTA HIT (Deadlock Fix)
                quotaHit = true;
                // Schedule retry 8 hours from now (Pacific midnight approximation or just safe backoff)
                const nextRetry = new Date(Date.now() + 8 * 60 * 60 * 1000).toISOString();

                await supabaseAdmin.from('indexing_queue').update({
                    status: 'retry',
                    updated_at: new Date().toISOString(),
                    response_status: 429,
                    last_error: "Daily Quota Exceeded (429)",
                    next_retry_at: nextRetry
                }).eq('id', item.id);
                failCount++;
            } else {
                // Other Error (403, 500, etc)
                // For 403 (Forbidden), it might be permanent. 
                // For 5xx, it might be transient.
                // Simple logic: 403 -> Failed, 5xx -> Retry (short backoff)? 
                // Let's stick to 'failed' for non-429 to be safe, user can manually re-queue.
                const statusText = res.statusText || 'Unknown Error';
                await supabaseAdmin.from('indexing_queue').update({
                    status: 'failed',
                    updated_at: new Date().toISOString(),
                    response_status: status,
                    last_error: `${status}: ${statusText}`.substring(0, 500)
                }).eq('id', item.id);
                failCount++;
            }
        } catch (e: unknown) {
            // Network error / Auth error
            // If it's a GaxiosError, it might have a response
            const errObj = e as Record<string, any>;
            const status = errObj.response?.status || 500;
            const msg = e instanceof Error ? e.message : 'Unknown Error';

            if (status === 429) {
                quotaHit = true;
                const nextRetry = new Date(Date.now() + 8 * 60 * 60 * 1000).toISOString();
                await supabaseAdmin.from('indexing_queue').update({
                    status: 'retry',
                    updated_at: new Date().toISOString(),
                    response_status: 429,
                    last_error: `Quota (Exception): ${msg}`,
                    next_retry_at: nextRetry
                }).eq('id', item.id);
            } else {
                await supabaseAdmin.from('indexing_queue').update({
                    status: 'failed',
                    updated_at: new Date().toISOString(),
                    last_error: msg
                }).eq('id', item.id);
            }
            failCount++;
        }
    }

    return {
        success: true,
        processed: claims.length,
        successCount,
        failCount,
        message: quotaHit
            ? `Stopped due to Quota Limit. Success: ${successCount}`
            : `Processed ${claims.length}. Success: ${successCount}, Failed: ${failCount}`
    };
}

// 6. Delete item
export async function deleteQueueItem(id: string) {
    const { error } = await supabaseAdmin.from('indexing_queue').delete().eq('id', id);
    if (error) throw new Error(error.message);
    return { success: true };
}

// 7. Schedule Fresh Content (The "Brain")
export async function scheduleFreshUrls(limit: number = 50) {
    // 1. Claim candidates via RPC
    const { data: candidates, error } = await supabaseAdmin
        .rpc('claim_fresh_candidates', { limit_count: limit });

    if (error) throw new Error(error.message);
    if (!candidates || candidates.length === 0) {
        return { success: true, count: 0, message: "No fresh content found." };
    }

    // 2. Construct URLs
    // Note: Adjust URL pattern based on your actual routes
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const items = candidates.map((c: any) => ({
        url: `${SITE_URL}/product/${c.seo_slug || c.id}`,
        priority: c.priority
    }));

    // 3. Queue them
    await internalQueueItems(items);

    return { success: true, count: items.length, message: `Scheduled ${items.length} fresh items.` };
}

'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import dynamic from 'next/dynamic';
import { useAuth } from '@/contexts/AuthContext';
import { AlertTriangle } from 'lucide-react';
import {
    getProducts,
    getWeeklySales,
} from '@/services/api';
import { getAdminOrders, getAdminDashboardStats, updateAdminOrderStatus } from '@/actions/admin';
import { Order, Product } from '@/types';

const OverviewTab = dynamic(() => import('@/components/admin/OverviewTab'));
const OrdersTab = dynamic(() => import('@/components/admin/OrdersTab'));
const InventoryTab = dynamic(() => import('@/components/admin/InventoryTab'));
const SeoTab = dynamic(() => import('@/components/admin/SeoTab'));

interface DashboardStats {
    totalRevenue: number;
    totalOrders: number;
    activeUsers: number;
}

export default function AdminDashboard() {
    const { user, isLoading: authLoading } = useAuth();
    const router = useRouter();

    const [activeTab, setActiveTab] = useState<'overview' | 'inventory' | 'orders' | 'seo'>('overview');
    const [stats, setStats] = useState<DashboardStats>({ totalRevenue: 0, totalOrders: 0, activeUsers: 0 });
    const [salesData, setSalesData] = useState<{ name: string; sales: number }[]>([]);
    const [orders, setOrders] = useState<Order[]>([]);
    const [products, setProducts] = useState<Product[]>([]);

    useEffect(() => {
        router.refresh();

        if (!authLoading) {
            if (!user) {
                router.replace('/login?from=/admin');
                return;
            }
            if (user.role === 'admin') {
                loadData();
            }
        }
    }, [user, authLoading, router]);

    const loadData = async () => {
        try {
            const [s, o, p, sales] = await Promise.all([
                getAdminDashboardStats(),
                getAdminOrders(),
                getProducts(),
                getWeeklySales(),
            ]);

            setStats(s as DashboardStats);
            setOrders(o);
            setProducts(p);
            setSalesData(sales);
        } catch (e) {
            console.error("Failed to load dashboard data", e);
        } catch (e) {
            console.error("Failed to load dashboard data", e);
        }
    };

    const handleStatusUpdate = async (orderId: string, newStatus: string) => {
        try {
            await updateAdminOrderStatus(orderId, newStatus);
            await loadData();
        } catch (e: unknown) {
            alert("Failed to update status: " + (e instanceof Error ? e.message : String(e)));
        }
    };

    if (authLoading) return <div className="min-h-screen flex items-center justify-center">Authentification...</div>;

    if (user && user.role !== 'admin') {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center bg-gray-100 p-4">
                <div className="bg-white p-8 rounded-lg shadow-md max-w-md w-full text-center">
                    <AlertTriangle className="h-16 w-16 text-yellow-500 mx-auto mb-4" />
                    <h1 className="text-2xl font-bold text-gray-900 mb-2">Acc├¿s Refus├®</h1>
                    <p className="text-gray-600 mb-6">
                        Vous n&apos;avez pas les permissions n├®cessaires pour acc├®der ├á cette page.
                    </p>
                    <button
                        onClick={() => router.push('/')}
                        className="bg-primary text-white px-6 py-2 rounded font-medium hover:bg-primary/90"
                    >
                        Retour ├á l&apos;accueil
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-100 p-8">
            <div className="max-w-7xl mx-auto">
                <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
                    <h1 className="text-2xl font-bold text-gray-900 font-serif">Admin Dashboard</h1>
                    <div className="flex space-x-2 bg-white p-1 rounded-lg shadow-sm border border-gray-200">
                        {(['overview', 'orders', 'inventory', 'seo'] as const).map((tab) => (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                className={`px-4 py-2 rounded-md text-sm font-medium capitalize transition-colors ${activeTab === tab ? 'bg-primary text-white shadow-sm' : 'text-gray-600 hover:bg-gray-50'
                                    }`}
                            >
                                {tab}
                            </button>
                        ))}
                    </div>
                </div>

                {activeTab === 'overview' && (
                    <OverviewTab stats={stats} salesData={salesData} productCount={products.length} />
                )}
                {activeTab === 'orders' && (
                    <OrdersTab orders={orders} onStatusUpdate={handleStatusUpdate} />
                )}
                {activeTab === 'inventory' && (
                    <InventoryTab products={products} onDataChanged={loadData} />
                )}
                {activeTab === 'seo' && (
                    <SeoTab />
                )}
            </div>
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useCart } from '@/contexts/CartContext';
import { useAuth } from '@/contexts/AuthContext';
import { createOrder, getMoroccanCities } from '@/services/api';
import { ShieldCheck, ShoppingBag, Truck, MapPin, AlertCircle, Check } from 'lucide-react';
import { validateMoroccanPhone, parseAddress } from '@/utils/helpers';
import { sanitizeInput, sanitizePhone, sanitizeEmail } from '@/utils/sanitize';
import { validatePassword } from '@/utils/passwordValidation';
import { getProductImage } from '@/utils/imageHelpers';
import Image from 'next/image';
import { useI18n } from '@/contexts/I18nContext';

export default function CheckoutPage() {
    const { items, total, clearCart } = useCart();
    const { user, signup, signInAnonymously } = useAuth();
    const router = useRouter();
    const { t } = useI18n();
    const [isProcessing, setIsProcessing] = useState(false);
    const [cities, setCities] = useState<string[]>(["Casablanca"]);
    const [submitError, setSubmitError] = useState('');

    // Shipping form data
    const [formData, setFormData] = useState({
        fullName: '',
        phone: '',
        city: 'Casablanca',
        address: ''
    });

    // Account creation toggle and fields
    const [wantsAccount, setWantsAccount] = useState(false);
    const [accountData, setAccountData] = useState({
        email: '',
        password: '',
        confirmPassword: ''
    });


    // Validation errors
    const [phoneError, setPhoneError] = useState('');
    const [emailError, setEmailError] = useState('');
    const [passwordError, setPasswordError] = useState('');
    const [confirmPasswordError, setConfirmPasswordError] = useState('');

    // Password strength
    const passwordStrength = validatePassword(accountData.password);

    useEffect(() => {
        getMoroccanCities().then(data => setCities(data));
    }, []);

    // Pre-fill for logged-in users
    useEffect(() => {
        if (user) {
            const { city, street } = parseAddress(user.address);
            setFormData(prev => ({
                ...prev,
                fullName: user.name || '',
                address: street,
                city: cities.includes(city) ? city : (cities[0] || 'Casablanca'),
                phone: user.phone || ''
            }));
        }
    }, [user, cities]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));

        if (name === 'phone') {
            if (value && !validateMoroccanPhone(value)) {
                setPhoneError('Num├®ro de t├®l├®phone invalide (ex: 0612345678)');
            } else {
                setPhoneError('');
            }
        }
    };

    const handleAccountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setAccountData(prev => ({ ...prev, [name]: value }));

        if (name === 'confirmPassword') {
            if (value !== accountData.password) {
                setConfirmPasswordError('Les mots de passe ne correspondent pas');
            } else {
                setConfirmPasswordError('');
            }
        }
    };

    const validateForm = () => {
        let isValid = true;

        if (!validateMoroccanPhone(formData.phone)) {
            setPhoneError('Num├®ro de t├®l├®phone invalide');
            isValid = false;
        }

        if (wantsAccount && !user) {
            if (!accountData.email || !accountData.email.includes('@')) {
                setEmailError('Email invalide');
                isValid = false;
            }
            if (!passwordStrength.isValid) {
                setPasswordError('Mot de passe trop faible');
                isValid = false;
            }
            if (accountData.password !== accountData.confirmPassword) {
                setConfirmPasswordError('Les mots de passe ne correspondent pas');
                isValid = false;
            }
        }

        return isValid;
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSubmitError('');

        if (!validateForm()) {
            return;
        }

        setIsProcessing(true);

        try {
            const sanitizedFullName = sanitizeInput(formData.fullName);
            const sanitizedAddress = sanitizeInput(formData.address);
            const sanitizedPhone = sanitizePhone(formData.phone);

            let userId = user?.id;
            let isNewAccount = false;

            // Handle Account Creation
            if (!user && wantsAccount) {
                try {
                    const result = await signup(
                        sanitizeEmail(accountData.email),
                        accountData.password,
                        sanitizedFullName,
                        sanitizedPhone,
                        `${formData.address}, ${formData.city}`
                    );

                    if (result?.user) {
                        userId = result.user.id;
                        isNewAccount = true;
                    }
                } catch (signupError: unknown) {
                    console.error('Signup failed:', signupError);
                    setSubmitError((signupError instanceof Error ? signupError.message : String(signupError)) || 'Erreur lors de la cr├®ation du compte');
                    setIsProcessing(false);
                    return; // Stop checkout if account creation fails explicitly requested
                }
            } else if (!userId) {
                // Anonymous Sign In
                try {
                    const anonResult = await signInAnonymously();
                    if (anonResult?.user) {
                        userId = anonResult.user.id;
                    }
                } catch (anonError) {
                    console.error('Anonymous sign-in failed:', anonError);
                }
            }

            const orderId = await createOrder({
                user_id: userId || null,
                items: items,
                total: total,
                status: 'pending',
                shipping_info: {
                    first_name: sanitizedFullName,
                    last_name: '',
                    address: sanitizedAddress,
                    city: formData.city,
                    phone: sanitizedPhone
                }
            });

            clearCart();
            router.push(`/order-confirmation?orderId=${orderId}&email=${wantsAccount ? encodeURIComponent(accountData.email) : ''}&newAccount=${isNewAccount}`);

        } catch (error: unknown) {
            console.error('Order creation failed:', error);
            setSubmitError(t('checkout.order_failure') + ': ' + (error instanceof Error ? error.message : 'Erreur inconnue'));
            window.scrollTo(0, 0);
        } finally {
            setIsProcessing(false);
        }
    };

    if (items.length === 0) {
        return (
            <div className="min-h-screen bg-gray-50 flex flex-col justify-center items-center p-4 text-center">
                <ShoppingBag className="h-16 w-16 text-gray-300 mb-4" />
                <h2 className="text-2xl font-bold text-gray-900 font-serif">{t('checkout.empty_cart')}</h2>
                <p className="text-gray-500 mt-2 mb-8">{t('checkout.add_items_to_start')}</p>
                <button onClick={() => router.push('/shop')} className="px-6 py-3 bg-primary text-white rounded-full font-medium hover:bg-primary/90 transition-colors">
                    {t('checkout.empty_action')}
                </button>
            </div>
        );
    }

    return (
        <div className="bg-gray-50 min-h-screen py-12">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

                {submitError && (
                    <div className="mb-6 bg-red-50 border border-red-200 rounded-lg p-4 flex items-start gap-3">
                        <AlertCircle className="h-5 w-5 text-red-500 flex-shrink-0 mt-0.5" />
                        <div className="flex-1">
                            <h3 className="text-sm font-medium text-red-800">{t('checkout.order_failure')}</h3>
                            <p className="text-sm text-red-700 mt-1">{submitError}</p>
                            <p className="text-xs text-red-600 mt-2">
                                {t('checkout.please_screenshot')}
                            </p>
                            <a
                                href={`https://wa.me/212656201278?text=${encodeURIComponent('Bonjour, j\'ai une erreur: ' + submitError)}`}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="text-sm text-red-600 hover:text-red-700 underline mt-2 inline-block font-medium"
                            >
                                {t('checkout.contact_support')} ÔåÆ
                            </a>
                        </div>
                    </div>
                )}

                {user && (
                    <div className="mb-6 bg-green-50 border border-green-200 rounded-lg p-4 flex items-center gap-3">
                        <ShieldCheck className="h-5 w-5 text-green-600" />
                        <p className="text-green-800">
                            <span className="font-medium">{t('checkout.logged_in_as')} {user.email || user.name}</span>
