"use client";

import React, { createContext, useContext, useState, useEffect } from 'react';
import frMessages from '../../messages/fr.json';
import enMessages from '../../messages/en.json';
import arMessages from '../../messages/ar.json';

export type Locale = 'fr' | 'en' | 'ar';

type Messages = typeof frMessages;

interface I18nContextType {
    locale: Locale;
    setLocale: (locale: Locale) => void;
    t: (key: string) => string;
    messages: Messages;
    dir: 'ltr' | 'rtl';
}

const I18nContext = createContext<I18nContextType | undefined>(undefined);

const messages: Record<Locale, Messages> = {
    fr: frMessages,
    en: enMessages,
    ar: arMessages,
};

export function I18nProvider({ children }: { children: React.ReactNode }) {
    const [locale, setLocaleState] = useState<Locale>('fr');

    // Load locale from localStorage on mount
    useEffect(() => {
        const saved = localStorage.getItem('locale') as Locale || 'fr';
        setLocaleState(saved);
    }, []);

    const setLocale = (newLocale: Locale) => {
        setLocaleState(newLocale);
        localStorage.setItem('locale', newLocale);
        // Update document direction for RTL
        document.documentElement.dir = newLocale === 'ar' ? 'rtl' : 'ltr';
        document.documentElement.lang = newLocale;
    };

    // Helper to get nested translation
    const t = (key: string): string => {
        const keys = key.split('.');
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
    let value: any = messages[locale];

        for (const k of keys) {
            value = value?.[k];
            if (value === undefined) {
                console.warn(`Translation missing: ${key} for locale ${locale}`);
                return key;
            }
        }

        return typeof value === 'string' ? value : key;
    };

    const dir = locale === 'ar' ? 'rtl' : 'ltr';

    // Update document direction on locale change
    useEffect(() => {
        document.documentElement.dir = dir;
        document.documentElement.lang = locale;
    }, [locale, dir]);

    return (
        <I18nContext.Provider value={{ locale, setLocale, t, messages: messages[locale], dir }}>
            {children}
        </I18nContext.Provider>
    );
}

export function useI18n() {
    const context = useContext(I18nContext);
    if (!context) {
        throw new Error('useI18n must be used within I18nProvider');
    }
    return context;
}

import { z } from 'zod';

// --- Primitives ---
const _UuidSchema = z.string().uuid().or(z.string().min(10)); // Relaxed UUID for safety
const UrlSchema = z.string().url().or(z.string().startsWith('/'));

// --- Block Schemas ---

// Base Block
const BaseBlockSchema = z.object({
    id: z.string().optional(),
});

// 1. Text Block
export const TextBlockSchema = BaseBlockSchema.extend({
    type: z.literal('text'),
    content: z.string(), // HTML string
    title: z.string().optional(),
});

// 2. Hero Block
export const HeroBlockSchema = BaseBlockSchema.extend({
    type: z.literal('hero'),
    heading: z.string(),
    subheading: z.string().optional(),
    image: UrlSchema.optional(),
});

// 3. Quote Block
export const QuoteBlockSchema = BaseBlockSchema.extend({
    type: z.literal('quote'),
    content: z.string(),
    author: z.string().optional(),
    role: z.string().optional(),
});

// 4. Alert Block
export const AlertBlockSchema = BaseBlockSchema.extend({
    type: z.literal('alert'),
    variant: z.enum(['info', 'warning', 'tip']).default('info'),
    content: z.string(),
});

// 5. Product Grid Block (The risky one)
export const ProductGridBlockSchema = BaseBlockSchema.extend({
    type: z.literal('product_grid'),
    productIds: z.array(z.string()).default([]),
    title: z.string().optional(),
});

// 6. Image Group (Future proofing)
export const ImageGroupBlockSchema = BaseBlockSchema.extend({
    type: z.literal('image_group'),
    images: z.array(z.object({
        url: UrlSchema,
        caption: z.string().optional()
    })).default([])
});

// Union of all blocks
export const BlogBlockSchema = z.discriminatedUnion('type', [
    TextBlockSchema,
    HeroBlockSchema,
    QuoteBlockSchema,
    AlertBlockSchema,
    ProductGridBlockSchema,
    ImageGroupBlockSchema
]);

// --- Main Content Schema ---

export const BlogContentSchema = z.object({
    theme: z.enum(['educational_deep_dive', 'product_showcase', 'listicle']).default('educational_deep_dive'),
    blocks: z.array(BlogBlockSchema).default([]),
    references: z.array(z.object({
        text: z.string(),
        url: z.string().optional()
    })).optional().default([])
});

// --- Parsing Helper ---

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function parseBlogContent(input: any): z.infer<typeof BlogContentSchema> | null {
    try {
        // Case 1: Input is already an object
        if (typeof input === 'object' && input !== null) {
            return BlogContentSchema.parse(input);
        }

        // Case 2: Input is a string (legacy or double-encoded)
        if (typeof input === 'string') {
            const parsed = JSON.parse(input);
            return BlogContentSchema.parse(parsed);
        }

        return null; // Unknown format
    } catch (e) {
        console.warn("Zod Validation Failed:", e);
        return null;
    }
}

// Export Types derived from Zod (to replace manual types.ts eventually)
export type SafeBlogContent = z.infer<typeof BlogContentSchema>;
export type SafeBlogBlock = z.infer<typeof BlogBlockSchema>;
export type SafeBlogBlockType = SafeBlogBlock['type'];

import { supabase } from './supabase';

// Types
interface PushNotificationPayload {
    title: string;
    body: string;
    icon?: string;
    badge?: string;
    url?: string;
    tag?: string;
    data?: Record<string, unknown>;
}

interface SendResult {
    success: boolean;
    sent: number;
    failed: number;
    errors: string[];
}

/**
 * Send push notification to a specific user
 * Note: This requires the web-push library on the server side
 * For client-side, this prepares the payload for a Supabase Edge Function
 */
export const sendNotificationToUser = async (
    userId: string,
    payload: PushNotificationPayload
): Promise<SendResult> => {
    try {
        // Call Supabase Edge Function to send the notification
        const { data, error } = await supabase.functions.invoke('send-push-notification', {
            body: {
                userId,
                notification: payload,
            },
        });

        if (error) {
            return { success: false, sent: 0, failed: 1, errors: [error.message] };
        }

        return data as SendResult;
    } catch (e: unknown) {
        const errorMessage = e instanceof Error ? e.message : 'Unknown error';
        return { success: false, sent: 0, failed: 1, errors: [errorMessage] };
    }
};

/**
 * Send push notification to all active subscribers
 */
export const sendNotificationToAll = async (
    payload: PushNotificationPayload
): Promise<SendResult> => {
    try {
        const { data, error } = await supabase.functions.invoke('send-push-notification', {
            body: {
                broadcast: true,
                notification: payload,
            },
        });

        if (error) {
            return { success: false, sent: 0, failed: 0, errors: [error.message] };
        }

        return data as SendResult;
    } catch (e: unknown) {
        const errorMessage = e instanceof Error ? e.message : 'Unknown error';
        return { success: false, sent: 0, failed: 0, errors: [errorMessage] };
    }
};

